import React from 'react';
import ReactDOM from 'react-dom';


// components
import App from './App';


// style
import "./style/main.css"


// react router
import {
  BrowserRouter as Router,
  Route
} from "react-router-dom";



ReactDOM.render(
  <React.StrictMode>
    <Router>
        <Route exact path="/" component={App}/>
    </Router>
  </React.StrictMode>,
  document.getElementById('root')
);

